import { ConvexClient } from "convex/browser";
import type { FunctionReference } from "convex/server";

const VISITOR_ID_KEY = "tchadbox_visitor_id";

function getVisitorId(): string {
  if (typeof window === "undefined") return "";

  let visitorId = localStorage.getItem(VISITOR_ID_KEY);
  if (!visitorId) {
    visitorId = crypto.randomUUID();
    localStorage.setItem(VISITOR_ID_KEY, visitorId);
  }
  return visitorId;
}

export function useCart() {
  const config = useRuntimeConfig();
  const authStore = useAuthStore();

  // État local
  const cart = ref<any>(null);
  const isLoading = ref(false);
  const convex = ref<ConvexClient | null>(null);

  // Initialiser le client Convex
  onMounted(() => {
    if (config.public.convexUrl) {
      convex.value = new ConvexClient(config.public.convexUrl);
      subscribeToCart();
    }
  });

  onUnmounted(() => {
    convex.value?.close();
  });

  // Subscription temps réel au panier
  function subscribeToCart() {
    if (!convex.value) return;

    const visitorId = getVisitorId();

    convex.value.onUpdate(
      "cart:getCart" as unknown as FunctionReference<"query">,
      { visitorId },
      (updatedCart) => {
        cart.value = updatedCart;
      }
    );
  }

  // Charger le panier
  async function fetchCart() {
    if (!convex.value) return;

    isLoading.value = true;
    try {
      const visitorId = getVisitorId();
      cart.value = await convex.value.query("cart:getCart" as unknown as FunctionReference<"query">, { visitorId });
    } finally {
      isLoading.value = false;
    }
  }

  // Ajouter au panier
  async function addItem(product: {
    productId: string;
    variantId?: string;
    title: string;
    thumbnail?: string;
    price: number;
    quantity?: number;
  }) {
    if (!convex.value) return;

    await convex.value.mutation("cart:addItem" as unknown as FunctionReference<"mutation">, {
      visitorId: getVisitorId(),
      productId: product.productId,
      variantId: product.variantId,
      title: product.title,
      thumbnail: product.thumbnail,
      price: product.price,
      quantity: product.quantity || 1,
    });
  }

  // Mettre à jour quantité
  async function updateQuantity(itemId: string, quantity: number) {
    if (!convex.value) return;

    await convex.value.mutation("cart:updateQuantity" as unknown as FunctionReference<"mutation">, {
      itemId,
      quantity,
    });
  }

  // Supprimer item
  async function removeItem(itemId: string) {
    if (!convex.value) return;

    await convex.value.mutation("cart:removeItem" as unknown as FunctionReference<"mutation">, {
      itemId,
    });
  }

  // Vider le panier
  async function clearCart() {
    if (!convex.value) return;

    await convex.value.mutation("cart:clearCart" as unknown as FunctionReference<"mutation">, {
      visitorId: getVisitorId(),
    });
  }

  // Merger au login
  async function mergeOnLogin(userId: string) {
    if (!convex.value) return;

    await convex.value.mutation("cart:mergeCartOnLogin" as unknown as FunctionReference<"mutation">, {
      visitorId: getVisitorId(),
      userId,
    });
  }

  // Computed
  const items = computed(() => cart.value?.items || []);
  const totalItems = computed(() => cart.value?.totalItems || 0);
  const totalPrice = computed(() => cart.value?.totalPrice || 0);
  const isEmpty = computed(() => totalItems.value === 0);

  return {
    cart,
    items,
    totalItems,
    totalPrice,
    isEmpty,
    isLoading,
    fetchCart,
    addItem,
    updateQuantity,
    removeItem,
    clearCart,
    mergeOnLogin,
  };
}
import { defineStore } from 'pinia'
import type { Customer, Address, UserRole } from '~/types'
import { useAuth, useUser, useClerk } from '@clerk/vue'

interface AuthState {
  user: Customer | null
  isAuthenticated: boolean
  isLoading: boolean
  error: string | null
  sessionChecked: boolean
}

export const useAuthStore = defineStore('auth', {
  state: (): AuthState => ({
    user: null,
    isAuthenticated: false,
    isLoading: true, // Clerk starts loading immediately
    error: null,
    sessionChecked: false,
  }),

  // =============================================
  // GETTERS (Mostly untouched, driven by internal state)
  // =============================================
  getters: {
    fullName: (state): string => {
      if (!state.user) return ''
      return `${state.user.firstName} ${state.user.lastName || ''}`.trim()
    },

    initials: (state): string => {
      if (!state.user) return '?'
      const first = state.user.firstName?.[0] || ''
      const last = state.user.lastName?.[0] || ''
      return (first + last).toUpperCase() || '?'
    },

    defaultAddress: (state): Address | null => {
      if (!state.user?.addresses) return null
      return state.user.addresses.find(a => a.isDefault) || state.user.addresses[0] || null
    },

    hasAddresses: (state): boolean => {
      return (state.user?.addresses?.length || 0) > 0
    },

    userRole: (state): UserRole => {
      if (state.user?.role) {
          return state.user.role as UserRole;
      }
      return 'client'
    },

    isClient(): boolean {
      return this.userRole === 'client'
    },

    isLivreur(): boolean {
      return this.userRole === 'livreur'
    },

    isAdmin(): boolean {
      return this.userRole === 'admin' || this.userRole === 'super-admin'
    },

    isSuperAdmin(): boolean {
      return this.userRole === 'super-admin'
    },

    canAccessAdmin(): boolean {
      return ['admin', 'super-admin'].includes(this.userRole)
    },

    canAccessLivreur(): boolean {
      return ['livreur', 'admin', 'super-admin'].includes(this.userRole)
    },

    canManageTeam(): boolean {
      return this.isSuperAdmin
    },

    canViewFinances(): boolean {
      return this.isSuperAdmin
    },
  },

  actions: {
    getApiUrl() {
        const config = useRuntimeConfig()
        return config.public.apiUrl
    },

    async getApiHeaders() {
        const { getToken } = useAuth()
        let token = ''
        try {
            // Fetch fresh Clerk JWT to send to Laravel
            token = await getToken() || ''
        } catch(e) {
            console.error("Clerk Token fetch failed", e)
        }

        const headers: Record<string, string> = {
            'Accept': 'application/json',
            'Content-Type': 'application/json'
        }

        if (token) {
            headers['Authorization'] = `Bearer ${token}`
        }
        return headers
    },

    // =============================================
    // CORE INITIALIZATION WITH CLERK
    // =============================================
    async checkSession() {
        // Clerk handles session persistence automatically via cookies/localStorage
        // We sync Clerk's state to our Pinia state
        if (this.sessionChecked) return

        const { isLoaded, isSignedIn } = useAuth()
        const { user: clerkUser } = useUser()

        // Wait for Clerk to be fully loaded
        // This is simplified; in a real app you might use watch() on isLoaded
        if (isLoaded.value) {
            this.syncWithClerk(isSignedIn.value, clerkUser.value)
            this.sessionChecked = true
            this.isLoading = false
        }
    },

    syncWithClerk(isSignedIn: boolean | undefined, clerkUser: any) {
        this.isAuthenticated = !!isSignedIn

        if (isSignedIn && clerkUser) {
            // Extract standard metadata. For roles, you can set them in Clerk dashboard
            // under User -> Public Metadata, e.g., { "role": "admin" }
            const metadataRole = clerkUser.publicMetadata?.role as UserRole | undefined || 'client'

            this.user = {
                id: clerkUser.id,
                email: clerkUser.primaryEmailAddress?.emailAddress || '',
                firstName: clerkUser.firstName || '',
                lastName: clerkUser.lastName || '',
                phone: clerkUser.primaryPhoneNumber?.phoneNumber || '',
                roles: [{ name: metadataRole }], // Mock Spatie structure
                role: metadataRole,
                createdAt: clerkUser.createdAt ? new Date(clerkUser.createdAt).toISOString() : new Date().toISOString(),
                addresses: [], 
            }

            // Sync with backend (fetch fresh data from Laravel using Clerk Token)
            this.fetchUserProfile()

            // Link Convex Cart
            const { mergeOnLogin } = useCart()
            mergeOnLogin(this.user.id).catch(console.error)

        } else {
            this.user = null
        }
    },

    // =============================================
    // MODIFIED AUTH ACTIONS (Using Clerk)
    // =============================================
    async login(email: string, password: string) {
      this.isLoading = true
      this.error = null

      try {
        const { client, setActive } = useClerk()

        // Attempt Sign In via Clerk core API
        const signInAttempt = await client.signIn.create({
            identifier: email,
            password: password
        })

        if (signInAttempt.status === 'complete') {
            await setActive({ session: signInAttempt.createdSessionId })
            // Pinia syncs via the checkSession/watch loop in layout usually,
            // but we can force it here
            const { user } = useUser()
            this.syncWithClerk(true, user.value)
            return { success: true, role: this.userRole }
        } else {
            // Requires 2FA or email verification
            this.error = "Vérification d'email ou 2FA requise."
            return { success: false, error: this.error }
        }
      } catch (error: any) {
        // Clerk throws arrays of errors
        this.error = error.errors?.[0]?.message || 'Erreur de connexion'
        return { success: false, error: this.error }
      } finally {
        this.isLoading = false
      }
    },

    async register(data: {
      email: string
      password: string
      firstName: string
      lastName: string
      phone?: string
    }) {
      this.isLoading = true
      this.error = null

      try {
        const { client, setActive } = useClerk()

        // Custom Sign Up flow using Clerk API
        const signUpAttempt = await client.signUp.create({
            emailAddress: data.email,
            password: data.password,
            firstName: data.firstName,
            lastName: data.lastName,
            // phone requires phone verification in Clerk settings if strictly passed
        })

        await client.signUp.prepareEmailAddressVerification({ strategy: "email_code" })

        // If the user wants standard Clerk email verification, we navigate there.
        // For standard local development where email is turned off or auto-verified:
        if (signUpAttempt.status === 'complete') {
            await setActive({ session: signUpAttempt.createdSessionId })
            const { user } = useUser()
            this.syncWithClerk(true, user.value)
            return { success: true, requiresConfirmation: false }
        } else {
            // Usually returns 'missing_requirements' waiting for email code
            return { success: true, requiresConfirmation: true, pendingVerificationId: signUpAttempt.id }
        }

      } catch (error: any) {
        this.error = error.errors?.[0]?.message || 'Erreur lors de l\'inscription'
        return { success: false, error: this.error }
      } finally {
        this.isLoading = false
      }
    },

    async verifyEmail(code: string) {
        this.isLoading = true
        this.error = null
        try {
            const { client, setActive } = useClerk()
            const completeSignUp = await client.signUp.attemptEmailAddressVerification({ code })

            if (completeSignUp.status === 'complete') {
                 await setActive({ session: completeSignUp.createdSessionId })
                 const { user } = useUser()
                 this.syncWithClerk(true, user.value)
                 return { success: true }
            } else {
                 this.error = "Code invalide ou expiré."
                 return { success: false, error: this.error }
            }
        } catch (error: any) {
            this.error = error.errors?.[0]?.message || 'Erreur de vérification'
            return { success: false, error: this.error }
        } finally {
            this.isLoading = false
        }
    },

    async fetchUserProfile() {
         // With Clerk, frontend holds the truth for Identity.
         // We hit Laravel /api/user mainly to sync data if needed 
         // or get Laravel specific relationships (e.g. Addresses)
         try {
            const headers = await this.getApiHeaders();
            const response: any = await $fetch(`${this.getApiUrl()}/user`, {
                method: 'GET',
                headers: headers
            })
            // Update local user with fresh Laravel data if needed
            // Example: this.user.addresses = response.addresses;
         } catch(e) {
             console.log("Could not fetch Laravel profile (expected if user just created)", e);
         }
    },


    async updateProfile(updates: Partial<{
      firstName: string
      lastName: string
      phone: string
    }>) {
      if (!this.user) return { success: false, error: 'Non connecté' }
      try {
        const { user } = useUser()
        if (user.value) {
            await user.value.update({
                firstName: updates.firstName,
                lastName: updates.lastName
            })
            // Update local state
            if (updates.firstName) this.user.firstName = updates.firstName
            if (updates.lastName) this.user.lastName = updates.lastName
            return { success: true }
        }
        return { success: false, error: "Clerk user object missing" }
      } catch(e: any) {
          return { success: false, error: e.errors?.[0]?.message || 'Erreur API' }
      }
    },

    async updateUserRole(userId: string, newRole: UserRole) {
      // NOTE: With Clerk, changing roles usually requires a Backend Admin API
      // to hit the Clerk Backend SDK directly and set `publicMetadata.role`.
      // Un utilisateur ne peut pas changer son propre rôle frontend.
      return { success: false, error: 'Non implémenté sur le backend pour Clerk' }
    },

    async logout() {
      try {
        const { signOut } = useClerk()
        await signOut()
      } catch (e) {
          console.error("Logout error", e)
      } finally {
        this.user = null
        this.isAuthenticated = false
        this.error = null

        const cartStore = useCartStore()
        if (cartStore && typeof cartStore.clearCart === 'function') {
           cartStore.clearCart()
        }

        navigateTo('/')
      }
    },

    async requestPasswordReset(email: string) {
       // Using Clerk API
       try {
           const { client } = useClerk()
           await client.signIn.create({
               strategy: 'reset_password_email_code',
               identifier: email,
           })
           return { success: true }
       } catch(e: any) {
           return { success: false, error: e.errors?.[0]?.message || 'Erreur' }
       }
    },

    clearError() {
      this.error = null
    },

    getRedirectPath(): string {
      if (!this.user) return '/'

      switch (this.userRole) {
        case 'super-admin':
        case 'admin':
          return '/admin'
        case 'livreur':
          return '/livreur'
        default:
          return '/compte'
      }
    },
  },
})
import { defineStore } from 'pinia'
import type { Product } from '~/types'

interface FavoriteItem {
  productId: string
  title: string
  price: number
  thumbnail?: string
  category?: string
  addedAt: string
}

interface FavoritesState {
  items: FavoriteItem[]
  isLoading: boolean
  synced: boolean
}

export const useFavoritesStore = defineStore('favorites', {
  state: (): FavoritesState => ({
    items: [],
    isLoading: false,
    synced: false,
  }),

  getters: {
    count: (state): number => state.items.length,

    isEmpty: (state): boolean => state.items.length === 0,

    isFavorite: (state) => (productId: string): boolean => {
      return state.items.some(item => item.productId === productId)
    },

    productIds: (state): string[] => {
      return state.items.map(item => item.productId)
    },
  },

  actions: {
    async initialize() {
      // Load from localStorage first
      this.loadFromStorage()

      // Then sync with server if authenticated
      const authStore = useAuthStore()
      if (authStore.isAuthenticated && authStore.user) {
        await this.syncWithServer()
      }
    },

    async toggleFavorite(product: Product | FavoriteItem) {
      const productId = 'productId' in product ? product.productId : product.id

      if (this.isFavorite(productId)) {
        await this.removeFromFavorites(productId)
      } else {
        await this.addToFavorites(product)
      }
    },

    async addToFavorites(product: Product | Omit<FavoriteItem, 'addedAt'>) {
      const productId = 'productId' in product ? product.productId : product.id

      // Prevent duplicates
      if (this.isFavorite(productId)) return

      const item: FavoriteItem = {
        productId,
        title: product.title,
        price: product.price,
        thumbnail: product.thumbnail,
        category: 'category' in product && product.category ? product.category.name : (product as any).category,
        addedAt: new Date().toISOString(),
      }

      this.items.push(item)
      this.saveToStorage()

      // Sync with server if authenticated
      const authStore = useAuthStore()
      if (authStore.isAuthenticated && authStore.user) {
        await this.addToServerFavorites(authStore.user.id, productId)
      }
    },

    async removeFromFavorites(productId: string) {
      const index = this.items.findIndex(item => item.productId === productId)

      if (index > -1) {
        this.items.splice(index, 1)
        this.saveToStorage()

        // Sync with server if authenticated
        const authStore = useAuthStore()
        if (authStore.isAuthenticated && authStore.user) {
          await this.removeFromServerFavorites(authStore.user.id, productId)
        }
      }
    },

    clearAll() {
      this.items = []
      this.saveToStorage()
    },

    // LocalStorage persistence
    saveToStorage() {
      if (process.client) {
        localStorage.setItem('tchadbox-favorites', JSON.stringify(this.items))
      }
    },

    loadFromStorage() {
      if (process.client) {
        const saved = localStorage.getItem('tchadbox-favorites')
        if (saved) {
          try {
            this.items = JSON.parse(saved)
          } catch (e) {
            console.error('Failed to parse favorites from storage:', e)
            this.items = []
          }
        }
      }
    },

    // Server sync methods
    async syncWithServer() {
      const authStore = useAuthStore()
      if (!authStore.user) return

      this.isLoading = true
      const { client } = useSupabase()

      try {
        // Get server favorites
        const { data: serverFavorites, error } = await client
          .from('favorites')
          .select('product_id, created_at')
          .eq('user_id', authStore.user.id)

        if (error) {
          console.error('Failed to fetch favorites:', error)
          return
        }

        // Merge local and server favorites
        const serverIds = new Set(serverFavorites?.map(f => f.product_id) || [])
        const localIds = new Set(this.items.map(i => i.productId))

        // Add local items to server that don't exist there
        for (const item of this.items) {
          if (!serverIds.has(item.productId)) {
            await this.addToServerFavorites(authStore.user.id, item.productId)
          }
        }

        // We don't remove local items that aren't on server
        // (user might have added them offline)

        this.synced = true
      } catch (error) {
        console.error('Failed to sync favorites:', error)
      } finally {
        this.isLoading = false
      }
    },

    async addToServerFavorites(userId: string, productId: string) {
      const { client } = useSupabase()

      try {
        await client
          .from('favorites')
          .upsert({
            user_id: userId,
            product_id: productId,
          }, {
            onConflict: 'user_id,product_id',
          })
      } catch (error) {
        console.error('Failed to add favorite to server:', error)
      }
    },

    async removeFromServerFavorites(userId: string, productId: string) {
      const { client } = useSupabase()

      try {
        await client
          .from('favorites')
          .delete()
          .match({
            user_id: userId,
            product_id: productId,
          })
      } catch (error) {
        console.error('Failed to remove favorite from server:', error)
      }
    },

    // Move item to cart
    moveToCart(productId: string) {
      const item = this.items.find(i => i.productId === productId)
      if (!item) return

      const cartStore = useCartStore()
      cartStore.addItem({
        id: item.productId,
        productId: item.productId,
        title: item.title,
        price: item.price,
        thumbnail: item.thumbnail,
        category: item.category,
      })

      // Optionally remove from favorites
      // this.removeFromFavorites(productId)
    },

    // Move all to cart
    moveAllToCart() {
      const cartStore = useCartStore()

      for (const item of this.items) {
        cartStore.addItem({
          id: item.productId,
          productId: item.productId,
          title: item.title,
          price: item.price,
          thumbnail: item.thumbnail,
          category: item.category,
        })
      }
    },
  },
})
